(171, 1, '2026-02-21 18:04:03', '2026-02-21 15:04:03', '<!-- wp:acf/nova-main {\"name\":\"acf/nova-main\",\"data\":{\"title\":\"От сертификации — \\u003cbr\\u003eк доверию и партнёрству\",\"_title\":\"field_6999c70cbd272\",\"desc\":\"В то время как другие сосредоточены на чём-то одном, «НОВА» видит картину целиком: мы — ваш единый центр компетенций для всех видов сертификации и декларирования, от пожарной безопасности до добровольных стандартов, с собственной лабораторией и доверием лидеров рынка, ведь большее доверие начинается с правильного выбора партнёра.\",\"_desc\":\"field_6999c76d8a5e7\",\"is_button_order\":\"1\",\"_is_button_order\":\"field_6999c7946e806\"},\"mode\":\"preview\"} /-->\n\n<!-- wp:acf/nova-partners {\"name\":\"acf/nova-partners\",\"data\":{\"title\":\"Наши партнеры — \\u003cbr\\u003eнаша особая гордость.\",\"_title\":\"field_6999ce7c60c42\",\"desc\":\"Мы не просто работаем с крупными российскими и международными компаниями — мы ценим и дорожим сотрудничеством с каждой из них. Их высокие стандарты делают нас лучше, а наша надёжность помогает им расти. Это партнёрство, которым можно гордиться.\",\"_desc\":\"field_6999cebf60c43\",\"partners_0_image\":177,\"_partners_0_image\":\"field_6999cf117cc98\",\"partners_1_image\":178,\"_partners_1_image\":\"field_6999cf117cc98\",\"partners_2_image\":179,\"_partners_2_image\":\"field_6999cf117cc98\",\"partners_3_image\":180,\"_partners_3_image\":\"field_6999cf117cc98\",\"partners_4_image\":181,\"_partners_4_image\":\"field_6999cf117cc98\",\"partners_5_image\":182,\"_partners_5_image\":\"field_6999cf117cc98\",\"partners_6_image\":183,\"_partners_6_image\":\"field_6999cf117cc98\",\"partners_7_image\":184,\"_partners_7_image\":\"field_6999cf117cc98\",\"partners_8_image\":185,\"_partners_8_image\":\"field_6999cf117cc98\",\"partners_9_image\":186,\"_partners_9_image\":\"field_6999cf117cc98\",\"partners_10_image\":187,\"_partners_10_image\":\"field_6999cf117cc98\",\"partners_11_image\":188,\"_partners_11_image\":\"field_6999cf117cc98\",\"partners_12_image\":189,\"_partners_12_image\":\"field_6999cf117cc98\",\"partners_13_image\":190,\"_partners_13_image\":\"field_6999cf117cc98\",\"partners_14_image\":191,\"_partners_14_image\":\"field_6999cf117cc98\",\"partners_15_image\":192,\"_partners_15_image\":\"field_6999cf117cc98\",\"partners_16_image\":193,\"_partners_16_image\":\"field_6999cf117cc98\",\"partners_17_image\":194,\"_partners_17_image\":\"field_6999cf117cc98\",\"partners_18_image\":195,\"_partners_18_image\":\"field_6999cf117cc98\",\"partners_19_image\":196,\"_partners_19_image\":\"field_6999cf117cc98\",\"partners\":20,\"_partners\":\"field_6999cef87cc97\"},\"mode\":\"preview\"} /-->\n\n<!-- wp:acf/nova-solutions {\"name\":\"acf/nova-solutions\",\"data\":{\"title\":\"Мы не создаем проблемы, мы их решаем\",\"_title\":\"field_6999d399f9d16\",\"desc\":\"Получите не просто документ, а надежного партнера, который берет на себя все сложности.\",\"_desc\":\"field_6999d3c3f9d17\",\"solutions_0_title\":\"Скорость и вовлеченность\",\"_solutions_0_title\":\"field_6999d3f3f9d19\",\"solutions_0_subtitle\":\"Быстрые ответы и полное погружение в задачу.\",\"_solutions_0_subtitle\":\"field_6999d436f9d1b\",\"solutions_0_desc\":\"Мы не просто исполнители. Мы — ваши заинтересованные представители, которые действуют оперативно и нацелены исключительно на ваш результат.\",\"_solutions_0_desc\":\"field_6999d41df9d1a\",\"solutions_0_image\":207,\"_solutions_0_image\":\"field_6999d51123a7c\",\"solutions_1_title\":\"Документы «под ключ»\",\"_solutions_1_title\":\"field_6999d3f3f9d19\",\"solutions_1_subtitle\":\"Сбор, подготовка и разработка всей необходимой документации.\",\"_solutions_1_subtitle\":\"field_6999d436f9d1b\",\"solutions_1_desc\":\"От технических условий и регламентов до внутренних стандартов предприятия. Мы создаем полный, безупречный пакет документов с нуля.\",\"_solutions_1_desc\":\"field_6999d41df9d1a\",\"solutions_1_image\":208,\"_solutions_1_image\":\"field_6999d51123a7c\",\"solutions_2_title\":\"Проактивный мониторинг\",\"_solutions_2_title\":\"field_6999d3f3f9d19\",\"solutions_2_subtitle\":\"Мы следим за рынком, а вы — в тренде.\",\"_solutions_2_subtitle\":\"field_6999d436f9d1b\",\"solutions_2_desc\":\"Наши эксперты круглосуточно отслеживают изменения законодательства, стандартов и тенденций. Вы получаете актуальные решения и защиту от неожиданных нововведений.\",\"_solutions_2_desc\":\"field_6999d41df9d1a\",\"solutions_2_image\":209,\"_solutions_2_image\":\"field_6999d51123a7c\",\"solutions_3_title\":\"Работаем на ваше время\",\"_solutions_3_title\":\"field_6999d3f3f9d19\",\"solutions_3_subtitle\":\"Круглосуточный процесс и ускоренные сроки.\",\"_solutions_3_subtitle\":\"field_6999d436f9d1b\",\"solutions_3_desc\":\"Наши лаборатории и офисы работают в интенсивном режиме. Мы ценим ваше время и делаем всё, чтобы сроки выпуска документов были минимальными.\",\"_solutions_3_desc\":\"field_6999d41df9d1a\",\"solutions_3_image\":210,\"_solutions_3_image\":\"field_6999d51123a7c\",\"solutions_4_title\":\"Полный логистический сервис\",\"_solutions_4_title\":\"field_6999d3f3f9d19\",\"solutions_4_subtitle\":\"Забудьте о сложной отправке образцов.\",\"_solutions_4_subtitle\":\"field_6999d436f9d1b\",\"solutions_4_desc\":\"Мы организуем и берем на себя всю логистику: от корректного отбора проб до их безопасной и своевременной доставки в аккредитованные лаборатории.\",\"_solutions_4_desc\":\"field_6999d41df9d1a\",\"solutions_4_image\":211,\"_solutions_4_image\":\"field_6999d51123a7c\",\"solutions\":5,\"_solutions\":\"field_6999d3d8f9d18\"},\"mode\":\"preview\"} /-->\n\n<!-- wp:acf/nova-steps {\"name\":\"acf/nova-steps\",\"data\":{\"title\":\"Этапы сертификации с НОВА\",\"_title\":\"field_6999f00449ff5\",\"steps_0_title\":\"Заявка\",\"_steps_0_title\":\"field_6999f03449ff7\",\"steps_0_desc\":\"оставляете данные на сайте\\u003cbr\\u003e (контакты + характеристики продукции/услуг)\",\"_steps_0_desc\":\"field_6999f09849ff8\",\"steps_1_title\":\"Подача в сертификационный орган / лабораторию\",\"_steps_1_title\":\"field_6999f03449ff7\",\"steps_1_desc\":\"передаем всё официально и отслеживаем процесс\",\"_steps_1_desc\":\"field_6999f09849ff8\",\"steps_2_title\":\"Консультация и подбор схемы 3\",\"_steps_2_title\":\"field_6999f03449ff7\",\"steps_2_desc\":\"мы анализируем вашу ситуацию и подбираем нужный документ\",\"_steps_2_desc\":\"field_6999f09849ff8\",\"steps_3_title\":\"Поддержка\\u003cbr\\u003e и сопровождение\",\"_steps_3_title\":\"field_6999f03449ff7\",\"steps_3_desc\":\"помощь при проверках, продление, перевыпуск, консультации\",\"_steps_3_desc\":\"field_6999f09849ff8\",\"steps_4_title\":\"Подготовка пакета документов\",\"_steps_4_title\":\"field_6999f03449ff7\",\"steps_4_desc\":\"оформление макета, сбор данных, протоколов, ТУ/ГОСТов, сведений о товаре\",\"_steps_4_desc\":\"field_6999f09849ff8\",\"steps_5_title\":\"Получение и передача документа\",\"_steps_5_title\":\"field_6999f03449ff7\",\"steps_5_desc\":\"вы получаете готовый сертификат / декларацию / свидетельство\",\"_steps_5_desc\":\"field_6999f09849ff8\",\"steps\":6,\"_steps\":\"field_6999f02549ff6\"},\"mode\":\"preview\"} /-->\n\n<!-- wp:acf/nova-documents {\"name\":\"acf/nova-documents\",\"data\":{\"title\":\"Все виды документов и услуг\",\"_title\":\"field_699aaaa6ad7d0\",\"desc\":\"Мы оформляем:\",\"_desc\":\"field_699aaadaad7d1\",\"docs_0_image_prev\":138,\"_docs_0_image_prev\":\"field_699aab72d6b6a\",\"docs_0_image_full\":139,\"_docs_0_image_full\":\"field_699aab7dd6b6b\",\"docs_0_doc_name\":\"Паспорт на изделие\",\"_docs_0_doc_name\":\"field_699aabd5d6b6c\",\"docs_0_file\":140,\"_docs_0_file\":\"field_699aabe4d6b6d\",\"docs_1_image_prev\":138,\"_docs_1_image_prev\":\"field_699aab72d6b6a\",\"docs_1_image_full\":139,\"_docs_1_image_full\":\"field_699aab7dd6b6b\",\"docs_1_doc_name\":\"Паспорт на изделие 2\",\"_docs_1_doc_name\":\"field_699aabd5d6b6c\",\"docs_1_file\":140,\"_docs_1_file\":\"field_699aabe4d6b6d\",\"docs_2_image_prev\":138,\"_docs_2_im